package SessionManager;

sub new {
    my ($class, %opts) = @_;
    my $self = bless {
        session_dir    => $opts{session_dir}    || $SESSION_DIR,
        session_prefix => $opts{session_prefix} || $SESSION_PREFIX,
        cookie_name    => $opts{cookie_name}    || $SESSION_COOKIE,
        expire         => $opts{expire}         || $SESSION_EXPIRE,
        cgi            => $opts{cgi}            || CGI->new(),
        session_id     => undef,
        data           => {},
        is_new         => 0,
    }, $class;

    $self->_init();
    return $self;
}

# Initialize session: load existing or create new
sub _init {
    my ($self) = @_;

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    if ($cookies{$self->{cookie_name}}) {
        my $sid = $cookies{$self->{cookie_name}}->value;
        # Validate session ID format (hex characters only for security)
        if ($sid =~ /^[a-f0-9]{64}$/) {
            $self->{session_id} = $sid;
        }
    }

    if ($self->{session_id} && $self->_session_file_exists()) {
        $self->_load_session();
