        } else {
            $self->{data}{_last_access} = time();
        }
    } else {
        $self->_create_new_session();
    }
}

# Generate a cryptographically strong session ID
sub _generate_session_id {
    my ($self) = @_;
    my $random_data = join('', map { rand() } 1..10);
    $random_data .= time() . $$ . rand(999999);
    return Digest::SHA::sha256_hex($random_data);
}

# Get the full path to session file
sub _session_file_path {
    my ($self) = @_;
    return File::Spec->catfile(
        $self->{session_dir},
        $self->{session_prefix} . $self->{session_id}
    );
}

# Check if session file exists
sub _session_file_exists {
    my ($self) = @_;
    return -f $self->_session_file_path();
}

# Create a new session
sub _create_new_session {
    my ($self) = @_;
    $self->{session_id} = $self->_generate_session_id();
    $self->{data} = {
        _created     => time(),
        _last_access => time(),
        _session_id  => $self->{session_id},
    };
