    }
}

# Save session data to file using Storable::lock_nstore
sub _save_session {
    my ($self) = @_;
    my $file = $self->_session_file_path();

    eval {
        lock_nstore($self->{data}, $file);
        chmod 0600, $file;  # Restrict permissions
    };
    if ($@) {
        warn "Failed to store session file '$file': $@";
        return 0;
    }
    return 1;
}

