# Set a session value
sub set {
    my ($self, $key, $value) = @_;
    # Prevent overwriting internal keys accidentally
    if ($key =~ /^_/ && $key !~ /^_user/) {
        warn "Cannot set internal session key '$key' directly";
        return 0;
    }
    $self->{data}{$key} = $value;
    return 1;
}

# Delete a session value
