    delete $self->{data}{$key};
}

# Get all session data (non-internal keys)
sub get_all {
    my ($self) = @_;
    my %public_data;
    for my $key (keys %{$self->{data}}) {
        next if $key =~ /^_(?!user)/;  # skip internal keys except _user*
        $public_data{$key} = $self->{data}{$key};
    }
    return \%public_data;
}

# Get session ID
sub session_id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if this is a new session
sub is_new {
