}

# Save session and generate cookie header
sub save {
    my ($self) = @_;
    $self->{data}{_last_access} = time();
    $self->_save_session();
}

# Get the session cookie
sub cookie {
    my ($self) = @_;
    my $cookie = CGI::Cookie->new(
        -name     => $self->{cookie_name},
        -value    => $self->{session_id},
        -expires  => '+' . $self->{expire} . 's',
        -path     => '/',
        -httponly  => 1,
        -secure   => 0,  # Set to 1 in production with HTTPS
        -samesite => 'Strict',
    );
