}

# Destroy the session
sub destroy {
    my ($self) = @_;
    my $file = $self->_session_file_path();
    if (-f $file) {
        unlink $file or warn "Failed to delete session file '$file': $!";
    }
    $self->{data} = {};
    $self->{session_id} = undef;
}

# Regenerate session ID (useful after login to prevent session fixation)
sub regenerate_id {
    my ($self) = @_;
    my $old_file = $self->_session_file_path();

    # Generate new session ID
    $self->{session_id} = $self->_generate_session_id();
    $self->{data}{_session_id} = $self->{session_id};

    # Save with new ID
    $self->_save_session();

    # Remove old session file
    if (-f $old_file) {
        unlink $old_file or warn "Failed to delete old session file '$old_file': $!";
    }

    return $self->{session_id};
}

# Class method: Clean up expired sessions (garbage collection)
sub cleanup_expired {
    my ($class, %opts) = @_;
    my $dir    = $opts{session_dir}    || $SESSION_DIR;
    my $prefix = $opts{session_prefix} || $SESSION_PREFIX;
    my $expire = $opts{expire}         || $SESSION_EXPIRE;

    my $count = 0;
    opendir(my $dh, $dir) or do {
        warn "Cannot open session directory '$dir': $!";
        return 0;
    };

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /^\Q$prefix\E[a-f0-9]{64}$/;
        my $filepath = File::Spec->catfile($dir, $entry);

        eval {
            my $data = retrieve($filepath);
            if ($data->{_last_access} &&
                (time() - $data->{_last_access}) > $expire) {
                unlink $filepath;
                $count++;
            }
        };
        if ($@) {
            # Corrupted session file, remove it
            unlink $filepath;
            $count++;
        }
    }
    closedir($dh);
    return $count;
}

